     1→import React, { FC, useCallback, useRef, useMemo } from 'react';
     2→import { useFocusEffect, useNavigation } from '@react-navigation/native';
     3→import { Dimensions } from 'react-native';
     4→import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
     5→import { ScreenProps } from '../../routes/Models';
     6→import { eventScreenViewV3, eventModalView, eventSelectContent } from '~/constants/functions';
     7→import MyOrdersDetailView from './view';
     8→import { useShallow } from "zustand/react/shallow";
     9→import { useRootStore } from '../../store';
    10→import { OrderDetailStatus, TransactionType } from '../../store/rewardProgram/models';
    11→import { getOrderDetail } from '../../store/rewardProgram/services';
    12→import { formatToCurrency } from '../../utils/functions';
    13→import { moment } from '../../services/moment';
    14→import {
    15→  getTransactionGainType,
    16→  getFormattedPointsValue,
    17→  getFormattedHighlightText,
    18→  getFormattedPointsValueForMarketplace,
    19→  getPaymentTypeLabel,
    20→  getMarketplaceTitle,
    21→  getCleanedImageUrl,
    22→} from './utils';
    23→import { MarketplaceContentData, MarketplaceItemData, STATUS_COLORS } from './Models';
    24→
    25→const MyOrdersDetails: FC<ScreenProps<'MyOrdersDetails'>> = ({
    26→  navigation,
    27→  route,
    28→}) => {
    29→  const hasFocused = useRef(false);
    30→  const modalizeRef = useRef<PropsModalizeRef>(null);
    31→  const modalizeRefInfo = useRef<PropsModalizeRef>(null);
    32→  
    33→  const { orderDetail, orderDetailActions } =
    34→    useRootStore(
    35→      useShallow((state) => ({
    36→        orderDetail: state.orderDetail,
    37→        orderDetailActions: state.orderDetailActions,
    38→      })),
    39→    );
    40→
    41→  const transactionId = route.params?.transactionId;
    42→  const passedType = route.params?.type;
    43→  const passedIcon = route.params?.icon;
    44→  const passedStatus = route.params?.status;
    45→  const passedOrigination = route.params?.origination;
    46→
    47→  useFocusEffect(
    48→    useCallback(() => {
    49→      if (!hasFocused.current) {
    50→        eventScreenViewV3(  
    51→          'detalhe_pedido',
    52→          'hub_recompensas_spmais',
    53→          'monetizacao',
    54→          {
    55→            location_1: 'monetizacao',
    56→            location_2: 'hub_recompensas_spmais',
    57→            location_3: 'detalhe_pedido',
    58→          });
    59→        hasFocused.current = true;
    60→      }
    61→      
    62→      if (transactionId) {
    63→        orderDetailActions.reset();
    64→        getOrderDetail({ transactionId });
    65→      }
    66→      
    67→      return () => {
    68→        hasFocused.current = false;
    69→        orderDetailActions.reset();
    70→      };
    71→    }, [transactionId, orderDetailActions])
    72→  );
    73→
    74→  const handleGoBack = () => {
    75→    navigation.goBack();
    76→  };
    77→
    78→  const handleOpenReportProblem = () => {
    79→    eventSelectContent({
    80→      content_type: 'cta',
    81→      content_id: 'relatar_problema',
    82→      location_1: 'monetizacao',
    83→      location_2: 'hub_recompensas_spmais',
    84→      location_3: 'detalhe_pedido',
    85→    });
    86→   
    87→    eventModalView({
    88→      content_id: 'contato_telefones',
    89→      location_1: 'monetizacao',
    90→      location_2: 'hub_recompensas_spmais',
    91→      location_3: 'detalhe_pedido',
    92→    });
    93→
    94→    modalizeRef.current?.open?.();
    95→  };
    96→
    97→  const handleCloseReportProblem = () => {
    98→    modalizeRef.current?.close?.();
    99→  };
   100→
   101→  const handleOpenInfo = () => {
   102→    modalizeRefInfo.current?.open?.();
   103→  };
   104→
   105→  const handleCloseInfo = () => {
   106→    modalizeRefInfo.current?.close?.();
   107→  };
   108→
   109→  const isLoading = orderDetail.status === OrderDetailStatus.LOADING;
   110→  const hasError = orderDetail.status === OrderDetailStatus.ERROR;
   111→  const { height } = Dimensions.get('window');
   112→
   113→  const handleRetry = () => {
   114→    if (transactionId) {
   115→      getOrderDetail({ transactionId });
   116→    }
   117→  };
   118→
   119→  const transaction = orderDetail.orderDetail;
   120→  
   121→  const isValidTransactionType = (type: string | undefined): type is TransactionType => {
   122→    return type === 'CREDIT' || type === 'RESCUE' || type === 'EXPIRED' || type === 'REFUNDED';
   123→  };
   124→  
   125→  const enrichedTransaction = transaction ? {
   126→    ...transaction,
   127→    type: isValidTransactionType(passedType) ? passedType : transaction.type,
   128→    icon: passedIcon || transaction.icon,
   129→    status: passedStatus || transaction.status,
   130→    details: {
   131→      ...transaction.details,
   132→      provider: passedOrigination || transaction.details?.provider || '',
   133→    },
   134→  } : undefined;
   135→
   136→  const isCashback = passedType === 'RESCUE';
   137→
   138→  const processedData = useMemo(() => {
   139→    if (!enrichedTransaction) {
   140→      return {
   141→        cardTitle: '',
   142→        formattedPointsValue: '',
   143→        highlightText: '',
   144→        formattedCurrencyValue: '',
   145→        marketplaceContent: undefined,
   146→        showOrderNumber: false,
   147→        showStatus: false,
   148→        showValue: false,
   149→      };
   150→    }
   151→
   152→    const gainType = getTransactionGainType(enrichedTransaction);
   153→    const formattedCurrencyValue = formatToCurrency(enrichedTransaction.currencyValue);
   154→    const marketplaceValuePoints = enrichedTransaction?.marketplace?.valuePoints;
   155→    const formattedPointsValue = marketplaceValuePoints !== undefined && marketplaceValuePoints !== null
   156→      ? `- ${getFormattedPointsValueForMarketplace(marketplaceValuePoints)}`
   157→      : getFormattedPointsValue(enrichedTransaction.amount, enrichedTransaction.type);
   158→    const marketplaceTitle = getMarketplaceTitle(enrichedTransaction);
   159→    const cardTitle = marketplaceTitle || enrichedTransaction.description || '';
   160→    const highlightText = getFormattedHighlightText(enrichedTransaction.date, gainType, moment);
   161→
   162→    const isMarketplace = !!enrichedTransaction?.marketplace;
   163→    const marketplace = enrichedTransaction?.marketplace;
   164→
   165→    let marketplaceContent: MarketplaceContentData | undefined;
   166→    if (isMarketplace && marketplace) {
   167→      const firstOrder = marketplace.orders?.[0];
   168→      const firstPayment = marketplace.payments?.[0];
   169→      const vendorName = firstOrder?.vendor || '';
   170→
   171→      const items: MarketplaceItemData[] = [];
   172→      marketplace.orders?.forEach(order => {
   173→        order.items?.forEach(item => {
   174→          items.push({
   175→            name: item.name,
   176→            quantity: item.quantity,
   177→            valuePoints: getFormattedPointsValueForMarketplace(item.valuePoints),
   178→            imageUrl: item.imageUrl,
   179→            cleanedImageUrl: getCleanedImageUrl(item.imageUrl),
   180→          });
   181→        });
   182→      });
   183→
   184→      marketplaceContent = {
   185→        orderNumber: enrichedTransaction.id,
   186→        status: enrichedTransaction.status,
   187→        statusColor: enrichedTransaction.status ? (STATUS_COLORS[enrichedTransaction.status] || 'neutral') : undefined,
   188→        paymentType: firstPayment ? getPaymentTypeLabel(firstPayment.paymentType) : undefined,
   189→        shippingValuePoints: marketplace.shippingValuePoints !== undefined && marketplace.shippingValuePoints !== null
   190→          ? getFormattedPointsValueForMarketplace(marketplace.shippingValuePoints)
   191→          : undefined,
   192→        valuePoints: marketplace.valuePoints !== undefined && marketplace.valuePoints !== null
   193→          ? getFormattedPointsValueForMarketplace(marketplace.valuePoints)
   194→          : undefined,
   195→        vendorName: vendorName || undefined,
   196→        items,
   197→      };
   198→    }
   199→
   200→    return {
   201→      cardTitle,
   202→      formattedPointsValue,
   203→      highlightText,
   204→      formattedCurrencyValue,
   205→      marketplaceContent,
   206→      showOrderNumber: !isMarketplace,
   207→      showStatus: !isMarketplace,
   208→      showValue: !isMarketplace,
   209→    };
   210→  }, [enrichedTransaction]);
   211→
   212→  return (
   213→    <MyOrdersDetailView
   214→      handleGoBack={handleGoBack}
   215→      transaction={enrichedTransaction}
   216→      modalizeRef={modalizeRef}
   217→      modalizeRefInfo={modalizeRefInfo}
   218→      handleOpenReportProblem={handleOpenReportProblem}
   219→      handleCloseReportProblem={handleCloseReportProblem}
   220→      handleOpenInfo={handleOpenInfo}
   221→      handleCloseInfo={handleCloseInfo}
   222→      isLoading={isLoading}
   223→      hasError={hasError}
   224→      handleRetry={handleRetry}
   225→      isCashback={isCashback}
   226→      cardTitle={processedData.cardTitle}
   227→      formattedPointsValue={processedData.formattedPointsValue}
   228→      highlightText={processedData.highlightText}
   229→      formattedCurrencyValue={processedData.formattedCurrencyValue}
   230→      marketplaceContent={processedData.marketplaceContent}
   231→      showOrderNumber={processedData.showOrderNumber}
   232→      showStatus={processedData.showStatus}
   233→      showValue={processedData.showValue}
   234→      height={height}
   235→    />
   236→  );
   237→};
   238→
   239→export default MyOrdersDetails;
   240→
   241→

