     6→
     7→function getTransactionFromOrderDetail(
     8→  dto: OrderDetailDataDto,
     9→): PointsTransaction {
    10→  const items = dto.items || [];
    11→  const benefits = dto.benefits || [];
    12→
    13→  const totalValue = items.reduce(
    14→    (sum, item) => sum + item.unitaryValue * item.quantity,
    15→    0,
    16→  );
    17→
    18→  const fields: Array<{
    19→    label: string;
    20→    value: string;
    21→  }> = [];
    22→
    23→  if (items.length > 0) {
    24→    items.forEach((item, index) => {
    25→      fields.push({
    26→        label: `Item ${index + 1}`,
    27→        value: `${item.description} - ${item.quantity}x R$ ${item.unitaryValue.toFixed(2)}`,
    28→      });
    29→    });
    30→  }
    31→
    32→  if (benefits.length > 0) {
    33→    benefits.forEach((benefit, index) => {
    34→      fields.push({
    35→        label: `Benefício ${index + 1}`,
    36→        value: `${benefit.description} - R$ ${Math.abs(benefit.value).toFixed(2)}`,
    37→      });
    38→    });
    39→  }
    40→
    41→  return {
    42→    id: dto.id,
    43→    date: dto.date,
    44→    description: dto.description,
    45→    type: 'RESCUE',
    46→    amount: dto.amount,
    47→    currencyValue: totalValue > 0 ? totalValue : Math.abs(dto.amount),
    48→    icon: 'icon-cashback',
    49→    details: {
    50→      provider: 'Cashback',
    51→      extraInfo: '',
    52→      fields,
    53→    },
    54→    status: '',
    55→    marketplace: dto.marketplace,
    56→  };
    57→}
    58→
    59→export function getOrderDetailFromResponse(
    60→  response: Awaited<ReturnType<typeof getOrderDetailApi>>,
    61→): PointsTransaction | null {
    62→  const apiResponse = response?.data;
    63→
    64→  if (!apiResponse) {
    65→    return null;
    66→  }
    67→
    68→  const status = apiResponse.status;
    69→  const returnCode = status?.returnCode;
    70→
    71→  if (returnCode !== 200 && returnCode !== 0) {
    72→    return null;
    73→  }
    74→
    75→  const orderDetailData = apiResponse.data;
    76→
    77→  if (!orderDetailData) {
    78→    return null;
    79→  }
    80→
    81→  return getTransactionFromOrderDetail(orderDetailData);
    82→}
